import { NodeSDK } from "@opentelemetry/sdk-node";
import { LangfuseSpanProcessor } from "@langfuse/otel";
import { startActiveObservation } from "@langfuse/tracing";
import { LangfuseClient } from "@langfuse/client";
import * as fs from "fs";

async function main() {
  const runId = process.env.ZEALT_RUN_ID;
  if (!runId) {
    throw new Error("ZEALT_RUN_ID environment variable is required");
  }

  const otelSdk = new NodeSDK({
    spanProcessors: [new LangfuseSpanProcessor()],
  });
  otelSdk.start();

  const langfuse = new LangfuseClient();

  const traceName = `multi-score-demo-${runId}`;
  let traceId = "";

  await startActiveObservation(traceName, async (traceSpan) => {
    // traceSpan could be LangfuseSpan
    // In our test, traceSpan.traceId was available.
    // However, traceSpan.otelSpan.spanContext().traceId is safer if traceId is private. 
    // Wait, let's just use traceSpan.traceId, or getActiveTraceId() from @langfuse/tracing
    const { getActiveTraceId } = require('@langfuse/tracing');
    traceId = getActiveTraceId();

    await startActiveObservation("llm-call", async (genSpan) => {
      // Do nothing, just a nested generation
    }, { asType: "generation" });
  });

  // Attach scores
  await langfuse.score.create({
    traceId,
    name: "correctness",
    value: 0.92,
    dataType: "NUMERIC"
  });

  await langfuse.score.create({
    traceId,
    name: "sentiment",
    value: "positive",
    dataType: "CATEGORICAL"
  });

  await langfuse.score.create({
    traceId,
    name: "helpfulness",
    value: 1,
    dataType: "BOOLEAN"
  });

  await langfuse.flushAsync();
  await otelSdk.shutdown();

  fs.writeFileSync("/home/user/myproject/output.log", `Trace ID: ${traceId}\n`);
}

main().catch(console.error);

